import sys
from collections import defaultdict

MOD = 10**9 + 7

def read_line():
    return sys.stdin.readline().strip()

def read_int():
    return int(read_line())

def read_ints():
    return map(int, read_line().split())

n = read_int()
points = [tuple(read_ints()) for _ in range(n)]
x_to_indices = defaultdict(list)
y_to_indices = defaultdict(list)
for i, (x, y) in enumerate(points):
    x_to_indices[x].append(i)
    y_to_indices[y].append(i)

visited = [False] * n
result = 1

for i in range(n):
    if not visited[i]:
        queue = [i]
        visited[i] = True
        x_set = set()
        y_set = set()
        component_size = 0
        while queue:
            v = queue.pop()
            x, y = points[v]
            x_set.add(x)
            y_set.add(y)
            component_size += 1
            for u in x_to_indices[x]:
                if not visited[u]:
                    visited[u] = True
                    queue.append(u)
            for u in y_to_indices[y]:
                if not visited[u]:
                    visited[u] = True
                    queue.append(u)
        total_lines = len(x_set) + len(y_set)
        if component_size == total_lines - 1:
            result = (result * (pow(2, total_lines, MOD) - 1)) % MOD
        else:
            result = (result * pow(2, total_lines, MOD)) % MOD

print(result)
